#!/bin/bash

# Script de vérification de la connexion à la base de données
# Usage: ./verifier-base-de-donnees.sh

echo "🔍 Vérification de la connexion à la base de données..."
echo ""

# Couleurs
GREEN='\033[0;32m'
RED='\033[0;31m'
YELLOW='\033[1;33m'
BLUE='\033[0;34m'
NC='\033[0m'

BACKEND_URL="http://localhost:3001"

# Vérifier le mode démo
echo "📋 Configuration actuelle:"
if grep -q "DEMO_MODE=true" backend/config.env 2>/dev/null; then
    echo -e "${YELLOW}⚠️  MODE DÉMO ACTIVÉ${NC}"
    echo -e "   Le système utilise des données statiques (pas de MongoDB)"
    echo ""
    echo -e "${BLUE}💡 Pour activer MongoDB:${NC}"
    echo -e "   1. Modifier backend/config.env"
    echo -e "   2. Définir DEMO_MODE=false"
    echo -e "   3. Redémarrer le serveur"
    echo ""
    DEMO_MODE=true
else
    echo -e "${GREEN}✅ MODE PRODUCTION${NC}"
    echo -e "   Le système utilise MongoDB"
    DEMO_MODE=false
fi

# Vérifier MongoDB
echo "🗄️  Vérification de MongoDB:"

# Essayer différentes commandes MongoDB
if command -v mongosh &> /dev/null; then
    if mongosh --eval "db.adminCommand('ping')" --quiet 2>/dev/null | grep -q "ok.*1"; then
        echo -e "${GREEN}✅ MongoDB est accessible (mongosh)${NC}"
        MONGO_AVAILABLE=true
    else
        echo -e "${RED}❌ MongoDB n'est pas accessible${NC}"
        MONGO_AVAILABLE=false
    fi
elif command -v mongo &> /dev/null; then
    if mongo --eval "db.adminCommand('ping')" --quiet 2>/dev/null | grep -q "ok.*1"; then
        echo -e "${GREEN}✅ MongoDB est accessible (mongo)${NC}"
        MONGO_AVAILABLE=true
    else
        echo -e "${RED}❌ MongoDB n'est pas accessible${NC}"
        MONGO_AVAILABLE=false
    fi
else
    echo -e "${YELLOW}⚠️  MongoDB CLI non trouvé${NC}"
    MONGO_AVAILABLE=false
fi

# Vérifier la connexion via l'API
echo ""
echo "🌐 Vérification via l'API Backend:"
if curl -s "$BACKEND_URL/api/health" > /dev/null 2>&1; then
    HEALTH=$(curl -s "$BACKEND_URL/api/health")
    echo -e "${GREEN}✅ Backend accessible${NC}"
    echo "   Réponse: $HEALTH"
else
    echo -e "${RED}❌ Backend non accessible${NC}"
fi

# Vérifier les modèles Mongoose
echo ""
echo "📦 Modèles Mongoose disponibles:"
MODELS_COUNT=$(find backend/src/models backend/models -name "*.js" -type f 2>/dev/null | wc -l | tr -d ' ')
echo -e "${BLUE}   $MODELS_COUNT modèles trouvés${NC}"

if [ $MODELS_COUNT -gt 0 ]; then
    echo ""
    echo "   Liste des modèles:"
    find backend/src/models backend/models -name "*.js" -type f 2>/dev/null | while read model; do
        MODEL_NAME=$(basename "$model" .js)
        echo -e "   - ${GREEN}✅${NC} $MODEL_NAME"
    done
fi

# Vérifier Prisma
echo ""
echo "🔧 Vérification Prisma:"
if [ -f "backend/prisma/schema.prisma" ]; then
    echo -e "${GREEN}✅ Schema Prisma trouvé${NC}"
    PRISMA_MODELS=$(grep -c "^model " backend/prisma/schema.prisma 2>/dev/null || echo "0")
    echo -e "   ${BLUE}$PRISMA_MODELS modèles Prisma${NC}"
    
    if [ -d "backend/node_modules/@prisma/client" ]; then
        echo -e "${GREEN}✅ Prisma Client installé${NC}"
    else
        echo -e "${YELLOW}⚠️  Prisma Client non généré${NC}"
        echo -e "   Exécutez: cd backend && npm run prisma:generate"
    fi
else
    echo -e "${RED}❌ Schema Prisma non trouvé${NC}"
fi

# Vérifier les routes qui utilisent MongoDB
echo ""
echo "🛣️  Routes utilisant MongoDB:"
ROUTES_WITH_MONGOOSE=$(grep -r "mongoose\|MongoDB\|mongoose\.model\|mongoose\.connect" backend/src/routes --include="*.js" 2>/dev/null | wc -l | tr -d ' ')
echo -e "${BLUE}   $ROUTES_WITH_MONGOOSE références MongoDB dans les routes${NC}"

# Résumé
